1	type Item = { type: string };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const FIRST_INSURANCE_MULTIPLIER = 1.1;
6	const ADMIN_FEE = 5;
7	
8	const BASE_PRICE: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	};
14	
15	export function runScenario(scenario: unknown): unknown {
16	  const { steps } = scenario as Scenario;
17	  const item = steps[0].items[0];
18	  const basePrice = BASE_PRICE[item.type];
19	  const premium = Math.round(basePrice * FIRST_INSURANCE_MULTIPLIER) + ADMIN_FEE;
20	  return { results: [{ premium }] };
21	}
